def en_uzun_palindrom(metin):
    if not metin:
        return 0
    en = 1
    def genislet(sol, sag):
        while sol >= 0 and sag < len(metin) and metin[sol] == metin[sag]:
            sol -= 1
            sag += 1
        return sag - sol - 1
    for i in range(len(metin)):
        en = max(en, genislet(i, i), genislet(i, i + 1))
    return en
